import{_ as n,r as l,o as r,c as a,e as s,d as i,f as c,a as e,b as o}from"./app-21c97978.js";const p={},d=c("<p>新手引导系统是 MKFramework 中用于创建和管理游戏内新手引导流程的工具。它允许开发者设计步骤式的交互教程，帮助玩家熟悉游戏的操作和功能，它的新手引导系统有以下几个亮点：</p><ul><li><p><strong>🔄多实例支持</strong>：MKFramework的新手引导系统支持创建多个引导实例，允许开发者同时管理多个引导流程。</p></li><li><p><strong>➕步骤插入与删除</strong>：该引导系统支持在任意阶段插入或删除步骤，提供了灵活的引导流程控制。</p></li><li><p><strong>⏸️暂停与完成操作</strong>：开发者可以根据游戏逻辑需要，随时暂停或完成新手引导，以适应玩家的行为。</p></li><li><p><strong>🔄状态还原</strong>：当引导跳转到任意步骤后，系统支持状态还原，确保玩家可以继续引导而不会感到困惑。</p></li><li><p><strong>🔧步骤脚本分离</strong>：引导步骤脚本是分离的，支持组件式挂载，这意味着每个步骤可以独立编写和管理，使得引导流程的修改和扩展变得更加简单。</p></li><li><p><strong>🧩组件化</strong>：引导功能被设计为组件化，可以轻松地集成到游戏项目中，且不会和游戏本身的其他部分产生耦合。</p></li></ul><p>这些特点使得MKFramework的新手引导系统既灵活又强大，能够帮助开发者创建出符合不同游戏需求的引导流程。</p>",3),_=e("h2",{id:"api",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#api","aria-hidden":"true"},"#"),o(" API")],-1),u=e("ul",null,[e("li",null,[e("p",null,[e("code",null,"mk.guide_manage"),o(": 引导管理类，负责引导流程的控制。")])]),e("li",null,[e("p",null,[e("code",null,"mk.guide_step_base"),o(": 引导步骤基类，所有自定义引导步骤应继承此类。")])])],-1);function g(m,h){const t=l("AutoCatalog");return r(),a("div",null,[d,s(" more "),_,u,i(t)])}const k=n(p,[["render",g],["__file","index.html.vue"]]);export{k as default};
